-- ============================================================
-- AdaptiDNS Database Schema and Data
-- Generated from experimental data of Eksperimen 3
-- Dissertation: Budi Sunaryo, Universitas Andalas, 2026
-- ============================================================

CREATE DATABASE IF NOT EXISTS adaptidns
  DEFAULT CHARACTER SET utf8mb4
  DEFAULT COLLATE utf8mb4_unicode_ci;

USE adaptidns;

-- ------------------------------------------------------------
-- Table: penalty_logs
-- Records every bandwidth penalty applied to users
-- ------------------------------------------------------------
DROP TABLE IF EXISTS penalty_logs;
CREATE TABLE penalty_logs (
  id            INT            NOT NULL AUTO_INCREMENT,
  username      VARCHAR(50)    NOT NULL,
  ip_address    VARCHAR(20)    NOT NULL,
  penalty_type  VARCHAR(20)    NOT NULL COMMENT 'judi | porno | penipuan | whitelist',
  bandwidth_before VARCHAR(30) NOT NULL,
  bandwidth_after  VARCHAR(30) NOT NULL,
  applied_at    DATETIME       NOT NULL,
  reset_at      DATETIME       DEFAULT NULL,
  status        VARCHAR(20)    NOT NULL DEFAULT 'active' COMMENT 'active | reset',
  PRIMARY KEY (id),
  INDEX idx_username   (username),
  INDEX idx_penalty_type (penalty_type),
  INDEX idx_applied_at (applied_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

