-- ------------------------------------------------------------
-- Table: bandwidth_logs
-- Records every bandwidth change event (penalty and reset)
-- ------------------------------------------------------------
DROP TABLE IF EXISTS bandwidth_logs;
CREATE TABLE bandwidth_logs (
  id            INT            NOT NULL AUTO_INCREMENT,
  username      VARCHAR(50)    NOT NULL,
  ip_address    VARCHAR(20)    NOT NULL,
  old_bandwidth VARCHAR(30)    NOT NULL,
  new_bandwidth VARCHAR(30)    NOT NULL,
  change_type   VARCHAR(20)    NOT NULL COMMENT 'penalty | reset',
  reason        VARCHAR(100)   DEFAULT NULL,
  change_time   DATETIME       NOT NULL,
  PRIMARY KEY (id),
  INDEX idx_username    (username),
  INDEX idx_change_time (change_time)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

