-- ------------------------------------------------------------
-- Table: user_access
-- Records every DNS query and its classification result
-- ------------------------------------------------------------
DROP TABLE IF EXISTS user_access;
CREATE TABLE user_access (
  id              INT            NOT NULL AUTO_INCREMENT,
  username        VARCHAR(50)    NOT NULL,
  ip_address      VARCHAR(20)    NOT NULL,
  mac_address     VARCHAR(20)    DEFAULT NULL,
  domain          VARCHAR(255)   NOT NULL,
  access_time     DATETIME       NOT NULL,
  classification  VARCHAR(20)    NOT NULL COMMENT 'whitelist | judi | porno | penipuan',
  confidence      DECIMAL(6,4)   DEFAULT NULL,
  status          VARCHAR(20)    NOT NULL DEFAULT 'processed',
  bandwidth_before VARCHAR(30)   DEFAULT NULL,
  bandwidth_after  VARCHAR(30)   DEFAULT NULL,
  penalty_applied  TINYINT(1)    NOT NULL DEFAULT 0,
  penalty_type     VARCHAR(20)   DEFAULT NULL,
  penalty_value    VARCHAR(30)   DEFAULT NULL,
  PRIMARY KEY (id),
  INDEX idx_username       (username),
  INDEX idx_classification (classification),
  INDEX idx_access_time    (access_time),
  INDEX idx_domain         (domain(100))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

